sys_script_include.script:
var ImportSetUtil = Class.create();
ImportSetUtil.prototype = {
    initialize: function() {
    },

	getLastImportSetSysId: function() {
		var result = "";
		const dataSourceSysId = "31ec4194c37bf210c134bf12b401314c";
		var grImportSet = new GlideRecord("sys_import_set");
		grImportSet.addQuery("data_source", dataSourceSysId);
		grImportSet.orderByDesc("sys_created_on");
		grImportSet.setLimit(1);
		grImportSet.query();
		if(grImportSet.hasNext()) {
			grImportSet.next();
			result = grImportSet.getValue("sys_id");
		}
		return result;
	},

    type: 'ImportSetUtil'
};
